import React, { useState } from 'react';
import { X, ChevronLeft, ChevronRight, ZoomIn } from 'lucide-react';

// Placeholder images since real ones aren't available
const IMAGES = [
  "https://images.unsplash.com/photo-1486262715619-01b8c245a352?q=80&w=800&auto=format&fit=crop",
  "https://images.unsplash.com/photo-1498889444388-e67ea62c464b?q=80&w=800&auto=format&fit=crop",
