  "https://images.unsplash.com/photo-1552519507-da3b142c6e3d?q=80&w=800&auto=format&fit=crop",
  "https://images.unsplash.com/photo-1562259920-47afc305f369?q=80&w=800&auto=format&fit=crop",
];

const Gallery: React.FC = () => {
  const [lightboxOpen, setLightboxOpen] = useState(false);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  const openLightbox = (index: number) => {
    setCurrentImageIndex(index);
    setLightboxOpen(true);
    document.body.style.overflow = 'hidden';
  };

  const closeLightbox = () => {
    setLightboxOpen(false);
    document.body.style.overflow = 'auto';
  };

  const nextImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex((prev) => (prev + 1) % IMAGES.length);
  };

  const prevImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCurrentImageIndex((prev) => (prev - 1 + IMAGES.length) % IMAGES.length);
  };

  return (
    <section id="gallery" className="py-20 bg-gray-50">
      <div className="container mx-auto px-4">
        <div className="text-center mb-12">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900 mb-4">Nossa Galeria</h2>
          <p className="text-gray-600">Conheça nossa estrutura e alguns trabalhos realizados</p>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {IMAGES.map((src, index) => (
            <div 
              key={index} 
              className="relative group cursor-pointer overflow-hidden rounded-lg aspect-square"
              onClick={() => openLightbox(index)}
            >
              <img 
                src={src} 
                alt={`Galeria ${index + 1}`} 
                className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
              />
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                <ZoomIn className="text-white" size={32} />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Lightbox Overlay */}
      {lightboxOpen && (
        <div 
          className="fixed inset-0 z-[60] bg-black/95 flex items-center justify-center p-4"
          onClick={closeLightbox}
        >
          <button 
            className="absolute top-4 right-4 text-white hover:text-gray-300"
            onClick={closeLightbox}
          >
            <X size={40} />
          </button>

          <button 
            className="absolute left-4 text-white hover:text-gray-300 hidden md:block"
            onClick={prevImage}
          >
            <ChevronLeft size={48} />
          </button>

          <img 
            src={IMAGES[currentImageIndex]} 
            alt="Full screen" 
            className="max-h-[90vh] max-w-full rounded-md shadow-2xl"
            onClick={(e) => e.stopPropagation()}
          />

          <button 
            className="absolute right-4 text-white hover:text-gray-300 hidden md:block"
            onClick={nextImage}
          >
            <ChevronRight size={48} />
          </button>

          <div className="absolute bottom-4 left-0 right-0 text-center text-white text-sm">
            {currentImageIndex + 1} / {IMAGES.length}
          </div>
        </div>
      )}
    </section>
  );
};

export default Gallery;

import React, { useEffect, useState } from 'react';
import { Star, Quote } from 'lucide-react';
import { DEPOIMENTOS } from '../constants';

const Testimonials: React.FC = () => {
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setActiveIndex((current) => (current + 1) % DEPOIMENTOS.length);
    }, 5000); // Auto-scroll every 5 seconds
    return () => clearInterval(interval);
  }, []);

  return (
    <section id="testimonials" className="py-20 bg-brand-blue text-white">
      <div className="container mx-auto px-4">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-4xl font-bold mb-4">O Que Dizem Nossos Clientes</h2>
          <div className="flex justify-center gap-1 mb-2">
            {[1, 2, 3, 4, 5].map((s) => (
              <Star key={s} size={24} fill="#FACC15" className="text-yellow-400" />
            ))}
          </div>
          <p className="text-blue-100">Avaliação média de 4.7/5.0 baseada em 98 clientes</p>
        </div>

        <div className="max-w-4xl mx-auto relative overflow-hidden">
          <div 
            className="flex transition-transform duration-700 ease-in-out"
            style={{ transform: `translateX(-${activeIndex * 100}%)` }}
          >
            {DEPOIMENTOS.map((depoimento, index) => (
              <div key={index} className="w-full flex-shrink-0 px-4">
                <div className="bg-white text-gray-900 p-8 md:p-12 rounded-2xl shadow-xl relative">
                  <Quote className="absolute top-6 left-6 text-brand-blue/20 transform -scale-x-100" size={60} />

                  <div className="relative z-10 flex flex-col items-center text-center">
                    <p className="text-lg md:text-xl text-gray-700 italic mb-6">
                      "{depoimento.texto}"
                    </p>
                    <div className="flex gap-1 mb-3">
                      {[...Array(depoimento.stars)].map((_, i) => (
                        <Star key={i} size={16} fill="#FACC15" className="text-yellow-400" />
                      ))}
                    </div>
                    <h4 className="font-bold text-lg">{depoimento.nome}</h4>
                    <span className="text-sm text-gray-500 uppercase tracking-wide">Serviço: {depoimento.servico}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="flex justify-center gap-2 mt-8">
            {DEPOIMENTOS.map((_, idx) => (
              <button
                key={idx}
                onClick={() => setActiveIndex(idx)}
                className={`w-3 h-3 rounded-full transition-colors ${idx === activeIndex ? 'bg-white' : 'bg-white/40 hover:bg-white/60'}`}
                aria-label={`Go to testimonial ${idx + 1}`}
              />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Testimonials;

